{
  "name": "SpendWise iOS",
  "description": "A sophisticated iOS-style spending tracker that uses AI to categorize natural language transactions and visualize financial health with interactive charts."
}

export enum Category {
  Shopping = 'Shopping',
  Fitness = 'Fitness',
  Dining = 'Dining',
  Groceries = 'Groceries',
  Automotive = 'Automotive',
  Travel = 'Travel',
  Health = 'Health',
  Entertainment = 'Entertainment',
  Utilities = 'Utilities',
  Other = 'Other'
}

export type Timeframe = 'Month' | '6 Months' | '12 Months' | 'YTD';

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  category: Category;
  date: string; // ISO string
}

export interface Budget {
  monthlyLimit: number;
}

export interface ChartDataPoint {
  name: string;
  value: number;
  color: string;
}

import React from 'react';
import { 
  ShoppingBag, 
  Dumbbell, 
  Utensils, 
  ShoppingCart, 
  Car, 
  Plane, 
  HeartPulse, 
  Ticket, 
  Zap, 
  MoreHorizontal 
} from 'lucide-react';
import { Category } from './types';

export const CATEGORY_CONFIG: Record<Category, { icon: React.ReactNode; color: string }> = {
  [Category.Shopping]: { icon: <ShoppingBag size={18} />, color: '#FF2D55' },
  [Category.Fitness]: { icon: <Dumbbell size={18} />, color: '#5856D6' },
  [Category.Dining]: { icon: <Utensils size={18} />, color: '#FF9500' },
  [Category.Groceries]: { icon: <ShoppingCart size={18} />, color: '#4CD964' },
  [Category.Automotive]: { icon: <Car size={18} />, color: '#8E8E93' },
  [Category.Travel]: { icon: <Plane size={18} />, color: '#5AC8FA' },
  [Category.Health]: { icon: <HeartPulse size={18} />, color: '#FF3B30' },
  [Category.Entertainment]: { icon: <Ticket size={18} />, color: '#AF52DE' },
