import React, { useMemo } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip } from 'recharts';
import { Transaction, Timeframe, Category } from '../types';
import { CATEGORY_CONFIG } from '../constants';
import { format, isWithinInterval, startOfMonth, endOfMonth, subMonths, startOfYear } from 'date-fns';

interface DashboardProps {
  transactions: Transaction[];
  budget: number;
  timeframe: Timeframe;
  onTimeframeChange: (t: Timeframe) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ transactions, budget, timeframe, onTimeframeChange }) => {
  const filteredTransactions = useMemo(() => {
    const now = new Date();
    let start: Date;
    const end = now;

    switch (timeframe) {
      case 'Month':
        start = startOfMonth(now);
        break;
      case '6 Months':
        start = startOfMonth(subMonths(now, 5));
        break;
      case '12 Months':
        start = startOfMonth(subMonths(now, 11));
        break;
      case 'YTD':
        start = startOfYear(now);
        break;
      default:
        start = startOfMonth(now);
    }

    return transactions.filter(t => 
      isWithinInterval(new Date(t.date), { start, end })
    );
  }, [transactions, timeframe]);

  const totalSpent = useMemo(() => 
    filteredTransactions.reduce((acc, curr) => acc + curr.amount, 0)
  , [filteredTransactions]);

  const currentMonthSpent = useMemo(() => {
    const now = new Date();
    return transactions
      .filter(t => isWithinInterval(new Date(t.date), { start: startOfMonth(now), end: endOfMonth(now) }))
      .reduce((acc, curr) => acc + curr.amount, 0);
  }, [transactions]);

  const categoryData = useMemo(() => {
    const totals: Record<string, number> = {};
    filteredTransactions.forEach(t => {
      totals[t.category] = (totals[t.category] || 0) + t.amount;
    });

    return Object.entries(totals).map(([name, value]) => ({
      name,
      value,
      color: CATEGORY_CONFIG[name as Category]?.color || '#8E8E93'
    })).sort((a, b) => b.value - a.value);
  }, [filteredTransactions]);

  const onTrackPercent = Math.min(Math.round((currentMonthSpent / budget) * 100), 100);
  const isOverBudget = currentMonthSpent > budget;

  return (
    <div className="flex flex-col gap-6 px-5 pb-24 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Monthly Summary Card */}
      <div className="bg-white rounded-3xl p-6 shadow-sm border border-gray-100 mt-4">
        <p className="text-gray-500 text-sm font-medium uppercase tracking-wider mb-1">Monthly Spending</p>
        <div className="flex justify-between items-baseline mb-4">
          <h2 className="text-4xl font-bold text-black">${currentMonthSpent.toFixed(2)}</h2>
          <span className={`text-xs font-semibold px-2 py-1 rounded-full ${isOverBudget ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'}`}>
            Budget: ${budget}
          </span>
        </div>

        <div className="w-full bg-gray-100 h-2.5 rounded-full overflow-hidden mb-2">
          <div 
            className={`h-full transition-all duration-1000 ease-out rounded-full ${isOverBudget ? 'bg-red-500' : 'bg-blue-500'}`}
            style={{ width: `${onTrackPercent}%` }}
          />
        </div>
        <p className="text-sm text-gray-500">
          {isOverBudget 
            ? `You're $${(currentMonthSpent - budget).toFixed(2)} over budget!` 
            : `You've used ${onTrackPercent}% of your budget.`}
        </p>
      </div>

      {/* Timeframe Selector */}
      <div className="flex bg-gray-200/50 p-1 rounded-xl">
        {(['Month', '6 Months', '12 Months', 'YTD'] as Timeframe[]).map((t) => (
          <button
            key={t}
            onClick={() => onTimeframeChange(t)}
            className={`flex-1 py-1.5 text-xs font-semibold rounded-lg transition-all ${
              timeframe === t ? 'bg-white shadow-sm text-black' : 'text-gray-500'
            }`}
          >
            {t}
          </button>
        ))}
      </div>

      {/* Charts Section */}
      <div className="bg-white rounded-3xl p-6 shadow-sm border border-gray-100">
        <h3 className="text-lg font-bold mb-4">Category Breakdown</h3>
        <div className="h-[240px] w-full flex items-center justify-center">
          {categoryData.length > 0 ? (
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={categoryData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                  animationBegin={0}
                  animationDuration={1500}
                >
                  {categoryData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip 
                  formatter={(value: number) => [`$${value.toFixed(2)}`, 'Spent']}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
              </PieChart>
            </ResponsiveContainer>
          ) : (
            <div className="text-gray-400 text-sm italic">No data for this timeframe</div>
          )}
        </div>

        {/* Legend */}
        <div className="mt-4 grid grid-cols-2 gap-3">
          {categoryData.slice(0, 4).map((data) => (
            <div key={data.name} className="flex items-center gap-2">
              <div className="w-3 h-3 rounded-full" style={{ backgroundColor: data.color }} />
              <div className="flex flex-col">
                <span className="text-xs font-medium text-gray-800">{data.name}</span>
                <span className="text-[10px] text-gray-400">${data.value.toFixed(2)}</span>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Bar Chart of Recent Spending */}
      <div className="bg-white rounded-3xl p-6 shadow-sm border border-gray-100">
        <h3 className="text-lg font-bold mb-4">Top Spending</h3>
        <div className="h-[200px] w-full">
           <ResponsiveContainer width="100%" height="100%">
            <BarChart data={categoryData.slice(0, 5)} layout="vertical">
              <XAxis type="number" hide />
              <YAxis 
                dataKey="name" 
                type="category" 
                axisLine={false} 
                tickLine={false} 
                tick={{ fontSize: 12, fontWeight: 500 }}
                width={80}
              />
              <Tooltip 
                formatter={(value: number) => [`$${value.toFixed(2)}`, '']}
                cursor={{ fill: 'transparent' }}
              />
              <Bar 
                dataKey="value" 
                radius={[0, 10, 10, 0]} 
                barSize={20}
                animationDuration={1500}
              >
                {categoryData.slice(0, 5).map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Send, Loader2, Sparkles, Plus, X } from 'lucide-react';
import { parseTransaction } from '../services/geminiService';
import { Transaction, Category } from '../types';
import { CATEGORY_CONFIG } from '../constants';

interface TransactionInputProps {
  onAddTransaction: (t: Omit<Transaction, 'id' | 'date'>) => void;
}

const TransactionInput: React.FC<TransactionInputProps> = ({ onAddTransaction }) => {
  const [input, setInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [suggestion, setSuggestion] = useState<{ description: string; amount: number; category: Category } | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isProcessing) return;

    setIsProcessing(true);
    try {
      const result = await parseTransaction(input);
      setSuggestion(result);
    } catch (error) {
      console.error(error);
    } finally {
      setIsProcessing(false);
    }
  };

  const confirmSuggestion = () => {
    if (suggestion) {
      onAddTransaction({
        description: suggestion.description,
        amount: suggestion.amount,
        category: suggestion.category
      });
      setSuggestion(null);
      setInput('');
    }
  };

  return (
    <div className="w-full">
      {!suggestion ? (
        <form onSubmit={handleSubmit} className="relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder='e.g., "Abercrombie jeans 50.99"'
            className="w-full bg-white border border-gray-200 rounded-2xl py-4 pl-5 pr-14 shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-lg font-medium"
          />
          <button
            type="submit"
            disabled={isProcessing || !input.trim()}
            className="absolute right-2 top-2 bottom-2 w-10 bg-blue-500 text-white rounded-xl flex items-center justify-center disabled:bg-gray-200 transition-colors"
          >
            {isProcessing ? <Loader2 className="animate-spin" size={20} /> : <Send size={20} />}
          </button>
          <div className="mt-2 flex items-center gap-1.5 px-1">
            <Sparkles size={14} className="text-blue-500" />
            <p className="text-[11px] font-medium text-gray-400 uppercase tracking-widest">Powered by Gemini</p>
          </div>
        </form>
      ) : (
        <div className="bg-white border-2 border-blue-500 rounded-2xl p-5 shadow-xl animate-in zoom-in-95 duration-200">
          <div className="flex justify-between items-start mb-4">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-blue-50 text-blue-500 rounded-lg">
                <Sparkles size={20} />
              </div>
              <h4 className="font-bold text-lg text-gray-900">AI Categorized</h4>
            </div>
            <button onClick={() => setSuggestion(null)} className="text-gray-400 hover:text-gray-600">
              <X size={20} />
            </button>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center py-3 border-y border-gray-50">
              <span className="text-gray-500 font-medium">Description</span>
              <input 
                value={suggestion.description}
                onChange={(e) => setSuggestion({...suggestion, description: e.target.value})}
                className="text-right font-bold focus:outline-none text-blue-600"
              />
            </div>

            <div className="flex justify-between items-center py-3 border-b border-gray-50">
              <span className="text-gray-500 font-medium">Category</span>
              <div className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full" style={{ backgroundColor: CATEGORY_CONFIG[suggestion.category].color }} />
                <select 
                  value={suggestion.category}
                  onChange={(e) => setSuggestion({...suggestion, category: e.target.value as Category})}
                  className="bg-transparent font-bold appearance-none focus:outline-none text-blue-600 text-right cursor-pointer"
                >
                  {Object.values(Category).map(cat => (
                    <option key={cat} value={cat}>{cat}</option>
                  ))}
                </select>
              </div>
            </div>

            <div className="flex justify-between items-center py-3 border-b border-gray-50">
              <span className="text-gray-500 font-medium">Amount</span>
              <div className="flex items-center text-blue-600 font-bold text-xl">
                <span>$</span>
                <input 
                  type="number"
                  step="0.01"
                  value={suggestion.amount}
                  onChange={(e) => setSuggestion({...suggestion, amount: parseFloat(e.target.value) || 0})}
                  className="w-24 text-right bg-transparent focus:outline-none"
                />
              </div>
            </div>
          </div>

          <button
            onClick={confirmSuggestion}
            className="w-full mt-6 bg-blue-500 text-white font-bold py-4 rounded-xl shadow-lg shadow-blue-200 active:scale-95 transition-all flex items-center justify-center gap-2"
          >
            <Plus size={20} />
            Add Transaction
          </button>
        </div>
      )}
    </div>
  );
};

export default TransactionInput;

import React from 'react';
import { Transaction } from '../types';
import { CATEGORY_CONFIG } from '../constants';
import { format } from 'date-fns';
import { Trash2 } from 'lucide-react';

interface TransactionListProps {
  transactions: Transaction[];
  onDelete: (id: string) => void;
}

const TransactionList: React.FC<TransactionListProps> = ({ transactions, onDelete }) => {
  const sortedTransactions = [...transactions].sort((a, b) => 
    new Date(b.date).getTime() - new Date(a.date).getTime()
  );

  return (
    <div className="flex flex-col gap-3 px-5 pb-32">
      <h3 className="text-xl font-bold mb-1">Recent Activity</h3>
      {sortedTransactions.length === 0 ? (
        <div className="bg-white rounded-2xl p-8 text-center border border-dashed border-gray-300">
          <p className="text-gray-400">No transactions yet.</p>
        </div>
      ) : (
        sortedTransactions.map((t) => {
          const config = CATEGORY_CONFIG[t.category];
          return (
            <div 
              key={t.id} 
              className="bg-white p-4 rounded-2xl flex items-center justify-between shadow-sm group hover:shadow-md transition-all active:scale-[0.98]"
            >
              <div className="flex items-center gap-4">
                <div 
                  className="w-11 h-11 rounded-full flex items-center justify-center text-white"
                  style={{ backgroundColor: config.color }}
                >
                  {config.icon}
                </div>
                <div>
                  <h4 className="font-bold text-gray-900 leading-tight">{t.description}</h4>
                  <p className="text-xs text-gray-500 font-medium mt-0.5">
                    {format(new Date(t.date), 'MMM d, h:mm a')} • {t.category}
                  </p>
                </div>
              </div>
              <div className="flex items-center gap-4">
                <span className="font-bold text-gray-900">-${t.amount.toFixed(2)}</span>
                <button 
                  onClick={() => onDelete(t.id)}
                  className="p-2 text-gray-300 hover:text-red-500 transition-colors"
                >
                  <Trash2 size={16} />
                </button>
              </div>
            </div>
          );
        })
      )}
    </div>
  );
};

export default TransactionList;

