import React, { useState, useEffect } from 'react';
import { LayoutGrid, PlusCircle, Settings, Wallet } from 'lucide-react';
import TopHeader from './components/TopHeader';
import Dashboard from './components/Dashboard';
import TransactionInput from './components/TransactionInput';
import TransactionList from './components/TransactionList';
import BudgetSetter from './components/BudgetSetter';
import { Transaction, Timeframe } from './types';
import { INITIAL_TRANSACTIONS } from './constants';

type Tab = 'Dashboard' | 'Add' | 'Transactions' | 'Budget';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('Dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('spendwise_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [budget, setBudget] = useState<number>(() => {
    const saved = localStorage.getItem('spendwise_budget');
    return saved ? parseFloat(saved) : 2000;
  });
  const [timeframe, setTimeframe] = useState<Timeframe>('Month');
  const [showBudgetModal, setShowBudgetModal] = useState(false);

  useEffect(() => {
    localStorage.setItem('spendwise_transactions', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('spendwise_budget', budget.toString());
  }, [budget]);

  const addTransaction = (t: Omit<Transaction, 'id' | 'date'>, date: string) => {
    const newTransaction: Transaction = {
      ...t,
      id: Math.random().toString(36).substr(2, 9),
      date: date,
    };
    setTransactions(prev => [newTransaction, ...prev]);
    setActiveTab('Transactions');
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'Dashboard':
        return (
          <Dashboard 
            transactions={transactions} 
            budget={budget} 
            timeframe={timeframe} 
            onTimeframeChange={setTimeframe} 
          />
        );
      case 'Add':
        return (
          <div className="px-5 pt-8 animate-in slide-in-from-bottom-4 duration-400">
            <h2 className="text-2xl font-bold mb-6">New Transaction</h2>
            <TransactionInput onAddTransaction={addTransaction} />
            <div className="mt-8">
              <p className="text-gray-400 text-sm font-medium mb-4 uppercase tracking-wider">Examples</p>
              <div className="flex flex-wrap gap-2">
                {['Abercrombie jeans $50', 'Starbucks Latte 5.50', 'Shell Fuel 45.00', 'Grocery run at Trader Joes $110'].map(ex => (
                  <div key={ex} className="bg-white border border-gray-100 rounded-xl px-4 py-2 text-sm text-gray-500 font-medium">
                    {ex}
                  </div>
                ))}
              </div>
            </div>
          </div>
        );
      case 'Transactions':
        return (
          <div className="animate-in slide-in-from-bottom-4 duration-400 mt-4">
             <TransactionList transactions={transactions} onDelete={deleteTransaction} />
          </div>
        );
      default:
        return null;
    }
  };

  const tabItems = [
    { id: 'Dashboard', icon: <LayoutGrid size={24} />, label: 'Overview' },
    { id: 'Add', icon: <PlusCircle size={28} className="text-blue-500" />, label: 'Add' },
    { id: 'Transactions', icon: <Wallet size={24} />, label: 'History' },
  ];

  return (
    <div className="max-w-md mx-auto h-screen bg-[#F2F2F7] flex flex-col relative shadow-2xl overflow-hidden border-x border-gray-200">
      <TopHeader 
        title={activeTab === 'Add' ? 'Add' : activeTab === 'Transactions' ? 'History' : 'Overview'} 
        rightElement={
          <button 
            onClick={() => setShowBudgetModal(true)}
            className="p-2 bg-gray-200/50 rounded-full text-gray-600 hover:bg-gray-200 active:scale-95 transition-all"
          >
            <Settings size={20} />
          </button>
        }
      />

      <main className="flex-1 overflow-y-auto hide-scrollbar">
        {renderContent()}
      </main>

      {/* Bottom Tab Bar */}
      <nav className="absolute bottom-0 left-0 right-0 bg-white/90 ios-blur pt-3 pb-8 px-8 flex justify-between items-center border-t border-gray-200 z-50">
        {tabItems.map((item) => (
          <button
            key={item.id}
            onClick={() => setActiveTab(item.id as Tab)}
            className={`flex flex-col items-center gap-1 transition-all active:scale-90 ${
              activeTab === item.id ? 'text-blue-500 scale-110' : 'text-gray-400'
            }`}
          >
            {item.icon}
            <span className="text-[10px] font-bold tracking-tight">{item.label}</span>
          </button>
        ))}
      </nav>

      {showBudgetModal && (
        <BudgetSetter 
          currentBudget={budget} 
          onUpdate={(val) => {
            setBudget(val);
            setShowBudgetModal(false);
          }}
          onClose={() => setShowBudgetModal(false)}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Send, Loader2, Sparkles, Plus, X, Calendar } from 'lucide-react';
import { parseTransaction } from '../services/geminiService';
import { Transaction, Category } from '../types';
import { CATEGORY_CONFIG } from '../constants';
import { format } from 'date-fns';

interface TransactionInputProps {
  onAddTransaction: (t: Omit<Transaction, 'id' | 'date'>, date: string) => void;
}

const TransactionInput: React.FC<TransactionInputProps> = ({ onAddTransaction }) => {
  const [input, setInput] = useState('');
  const [selectedDate, setSelectedDate] = useState(format(new Date(), 'yyyy-MM-dd'));
  const [isProcessing, setIsProcessing] = useState(false);
  const [suggestion, setSuggestion] = useState<{ description: string; amount: number; category: Category } | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isProcessing) return;

    setIsProcessing(true);
    try {
      const result = await parseTransaction(input);
      setSuggestion(result);
    } catch (error) {
      console.error(error);
    } finally {
      setIsProcessing(false);
    }
  };

  const confirmSuggestion = () => {
    if (suggestion) {
      // Use the selected date or a combination of date and current time
      const finalDate = new Date(selectedDate);
      const now = new Date();
      finalDate.setHours(now.getHours(), now.getMinutes(), now.getSeconds());

      onAddTransaction({
        description: suggestion.description,
        amount: suggestion.amount,
        category: suggestion.category
      }, finalDate.toISOString());

      setSuggestion(null);
      setInput('');
      setSelectedDate(format(new Date(), 'yyyy-MM-dd'));
    }
  };

  return (
    <div className="w-full">
      {!suggestion ? (
        <form onSubmit={handleSubmit} className="relative space-y-4">
          <div className="relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder='e.g., "Abercrombie jeans 50.99"'
              className="w-full bg-white border border-gray-200 rounded-2xl py-4 pl-5 pr-14 shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-lg font-medium"
            />
            <button
              type="submit"
              disabled={isProcessing || !input.trim()}
              className="absolute right-2 top-2 bottom-2 w-10 bg-blue-500 text-white rounded-xl flex items-center justify-center disabled:bg-gray-200 transition-colors"
            >
              {isProcessing ? <Loader2 className="animate-spin" size={20} /> : <Send size={20} />}
            </button>
          </div>

          <div className="flex items-center gap-3 bg-white border border-gray-200 rounded-2xl py-3 px-5 shadow-sm">
            <Calendar size={18} className="text-gray-400" />
            <div className="flex-1">
               <label className="text-[10px] font-bold text-gray-400 uppercase block mb-0.5">Transaction Date</label>
               <input 
                 type="date"
                 value={selectedDate}
                 onChange={(e) => setSelectedDate(e.target.value)}
                 className="w-full text-sm font-semibold bg-transparent focus:outline-none"
               />
            </div>
          </div>

          <div className="mt-2 flex items-center gap-1.5 px-1">
            <Sparkles size={14} className="text-blue-500" />
            <p className="text-[11px] font-medium text-gray-400 uppercase tracking-widest">Powered by Gemini</p>
          </div>
        </form>
      ) : (
        <div className="bg-white border-2 border-blue-500 rounded-2xl p-5 shadow-xl animate-in zoom-in-95 duration-200">
          <div className="flex justify-between items-start mb-4">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-blue-50 text-blue-500 rounded-lg">
                <Sparkles size={20} />
              </div>
              <h4 className="font-bold text-lg text-gray-900">AI Categorized</h4>
            </div>
            <button onClick={() => setSuggestion(null)} className="text-gray-400 hover:text-gray-600">
              <X size={20} />
            </button>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center py-3 border-y border-gray-50">
              <span className="text-gray-500 font-medium">Description</span>
              <input 
                value={suggestion.description}
                onChange={(e) => setSuggestion({...suggestion, description: e.target.value})}
                className="text-right font-bold focus:outline-none text-blue-600"
              />
            </div>

            <div className="flex justify-between items-center py-3 border-b border-gray-50">
              <span className="text-gray-500 font-medium">Category</span>
              <div className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full" style={{ backgroundColor: CATEGORY_CONFIG[suggestion.category].color }} />
                <select 
                  value={suggestion.category}
                  onChange={(e) => setSuggestion({...suggestion, category: e.target.value as Category})}
                  className="bg-transparent font-bold appearance-none focus:outline-none text-blue-600 text-right cursor-pointer"
                >
                  {Object.values(Category).map(cat => (
                    <option key={cat} value={cat}>{cat}</option>
                  ))}
                </select>
              </div>
            </div>

            <div className="flex justify-between items-center py-3 border-b border-gray-50">
              <span className="text-gray-500 font-medium">Date</span>
              <input 
                type="date"
                value={selectedDate}
                onChange={(e) => setSelectedDate(e.target.value)}
                className="text-right font-bold focus:outline-none text-blue-600 bg-transparent"
              />
            </div>

            <div className="flex justify-between items-center py-3 border-b border-gray-50">
              <span className="text-gray-500 font-medium">Amount</span>
              <div className="flex items-center text-blue-600 font-bold text-xl">
                <span>$</span>
                <input 
                  type="number"
                  step="0.01"
                  value={suggestion.amount}
                  onChange={(e) => setSuggestion({...suggestion, amount: parseFloat(e.target.value) || 0})}
                  className="w-24 text-right bg-transparent focus:outline-none"
                />
              </div>
            </div>
          </div>

          <button
            onClick={confirmSuggestion}
            className="w-full mt-6 bg-blue-500 text-white font-bold py-4 rounded-xl shadow-lg shadow-blue-200 active:scale-95 transition-all flex items-center justify-center gap-2"
          >
            <Plus size={20} />
            Add Transaction
          </button>
        </div>
      )}
    </div>
  );
};

export default TransactionInput;

import React, { useMemo } from 'react';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, 
  XAxis, YAxis, Tooltip, AreaChart, Area, CartesianGrid, Line 
} from 'recharts';
import { Transaction, Timeframe, Category } from '../types';
import { CATEGORY_CONFIG } from '../constants';
import { 
  format, isWithinInterval, startOfMonth, endOfMonth, 
  subMonths, startOfYear, eachDayOfInterval, isSameDay, differenceInDays
} from 'date-fns';

interface DashboardProps {
  transactions: Transaction[];
  budget: number;
  timeframe: Timeframe;
  onTimeframeChange: (t: Timeframe) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ transactions, budget, timeframe, onTimeframeChange }) => {
  const dateRange = useMemo(() => {
    const now = new Date();
    let start: Date;
    const end = now;

    switch (timeframe) {
      case 'Month':
        start = startOfMonth(now);
        break;
      case '6 Months':
        start = startOfMonth(subMonths(now, 5));
        break;
      case '12 Months':
        start = startOfMonth(subMonths(now, 11));
        break;
      case 'YTD':
        start = startOfYear(now);
        break;
      default:
        start = startOfMonth(now);
    }
    return { start, end };
  }, [timeframe]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => 
      isWithinInterval(new Date(t.date), dateRange)
    );
  }, [transactions, dateRange]);

  const currentMonthSpent = useMemo(() => {
    const now = new Date();
    const start = startOfMonth(now);
    const end = endOfMonth(now);
    return transactions
      .filter(t => isWithinInterval(new Date(t.date), { start, end }))
      .reduce((acc, curr) => acc + curr.amount, 0);
  }, [transactions]);

  // Generate Time Series Data
  const timeSeriesData = useMemo(() => {
    const days = eachDayOfInterval(dateRange);
    const totalDays = days.length;

    // Calculate multiplier for budget based on how many months are spanned
    // Simple version: if it's 6 months, ideal end is budget * 6
    let budgetMultiplier = 1;
    if (timeframe === '6 Months') budgetMultiplier = 6;
    if (timeframe === '12 Months') budgetMultiplier = 12;
    if (timeframe === 'YTD') budgetMultiplier = new Date().getMonth() + 1;

    const totalTargetBudget = budget * budgetMultiplier;
    const idealDailyStep = totalTargetBudget / (totalDays - 1 || 1);

    let cumulativeActual = 0;

    return days.map((day, index) => {
      const dailyTransactions = filteredTransactions.filter(t => isSameDay(new Date(t.date), day));
      const dailySum = dailyTransactions.reduce((acc, t) => acc + t.amount, 0);
      cumulativeActual += dailySum;

      return {
        date: format(day, totalDays > 31 ? 'MMM d' : 'd'),
        actual: cumulativeActual,
        ideal: idealDailyStep * index,
      };
    });
  }, [dateRange, filteredTransactions, budget, timeframe]);

  const categoryData = useMemo(() => {
    const totals: Record<string, number> = {};
    filteredTransactions.forEach(t => {
      totals[t.category] = (totals[t.category] || 0) + t.amount;
    });

    return Object.entries(totals).map(([name, value]) => ({
      name,
      value,
      color: CATEGORY_CONFIG[name as Category]?.color || '#8E8E93'
    })).sort((a, b) => b.value - a.value);
  }, [filteredTransactions]);

  const onTrackPercent = Math.min(Math.round((currentMonthSpent / budget) * 100), 100);
  const isOverBudget = currentMonthSpent > budget;

  return (
    <div className="flex flex-col gap-6 px-5 pb-24 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Monthly Summary Card */}
      <div className="bg-white rounded-3xl p-6 shadow-sm border border-gray-100 mt-4">
        <p className="text-gray-500 text-sm font-medium uppercase tracking-wider mb-1">Monthly Spending</p>
        <div className="flex justify-between items-baseline mb-4">
          <h2 className="text-4xl font-bold text-black">${currentMonthSpent.toFixed(2)}</h2>
          <span className={`text-xs font-semibold px-2 py-1 rounded-full ${isOverBudget ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'}`}>
            Budget: ${budget}
          </span>
        </div>

        <div className="w-full bg-gray-100 h-2.5 rounded-full overflow-hidden mb-2">
          <div 
            className={`h-full transition-all duration-1000 ease-out rounded-full ${isOverBudget ? 'bg-red-500' : 'bg-blue-500'}`}
            style={{ width: `${onTrackPercent}%` }}
          />
        </div>
        <p className="text-sm text-gray-500">
          {isOverBudget 
            ? `You're $${(currentMonthSpent - budget).toFixed(2)} over budget!` 
            : `You've used ${onTrackPercent}% of your budget.`}
        </p>
      </div>

      {/* Timeframe Selector */}
      <div className="flex bg-gray-200/50 p-1 rounded-xl">
        {(['Month', '6 Months', '12 Months', 'YTD'] as Timeframe[]).map((t) => (
          <button
            key={t}
            onClick={() => onTimeframeChange(t)}
            className={`flex-1 py-1.5 text-xs font-semibold rounded-lg transition-all ${
              timeframe === t ? 'bg-white shadow-sm text-black' : 'text-gray-500'
            }`}
          >
            {t}
          </button>
        ))}
      </div>

      {/* Spending Trend (Time Series) */}
      <div className="bg-white rounded-3xl p-6 shadow-sm border border-gray-100">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-bold">Spending Trend</h3>
          <div className="flex items-center gap-3">
             <div className="flex items-center gap-1">
               <div className="w-2 h-2 rounded-full bg-blue-500" />
               <span className="text-[10px] font-bold text-gray-400">ACTUAL</span>
             </div>
             <div className="flex items-center gap-1">
               <div className="w-2 h-0.5 bg-gray-300" />
               <span className="text-[10px] font-bold text-gray-400">TARGET</span>
             </div>
          </div>
        </div>
        <div className="h-[200px] w-full -ml-4">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={timeSeriesData}>
              <defs>
                <linearGradient id="colorActual" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.15}/>
                  <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid vertical={false} stroke="#F3F4F6" />
              <XAxis 
                dataKey="date" 
                axisLine={false} 
                tickLine={false} 
                tick={{ fontSize: 10, fill: '#9CA3AF' }} 
                minTickGap={20}
              />
              <YAxis hide domain={[0, 'auto']} />
              <Tooltip 
                contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                formatter={(value: number) => [`$${value.toFixed(2)}`]}
              />
              <Area 
                type="monotone" 
                dataKey="actual" 
                stroke="#3b82f6" 
                strokeWidth={3} 
                fillOpacity={1} 
                fill="url(#colorActual)" 
                animationDuration={2000}
              />
              <Line 
                type="monotone" 
                dataKey="ideal" 
                stroke="#D1D5DB" 
                strokeWidth={1.5} 
                strokeDasharray="5 5" 
                dot={false}
                animationDuration={2000}
              />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Charts Section */}
      <div className="bg-white rounded-3xl p-6 shadow-sm border border-gray-100">
        <h3 className="text-lg font-bold mb-4">Category Breakdown</h3>
        <div className="h-[240px] w-full flex items-center justify-center">
          {categoryData.length > 0 ? (
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={categoryData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                  animationBegin={0}
                  animationDuration={1500}
                >
                  {categoryData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip 
                  formatter={(value: number) => [`$${value.toFixed(2)}`, 'Spent']}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
              </PieChart>
            </ResponsiveContainer>
          ) : (
            <div className="text-gray-400 text-sm italic">No data for this timeframe</div>
          )}
        </div>

        {/* Legend */}
        <div className="mt-4 grid grid-cols-2 gap-3">
          {categoryData.slice(0, 4).map((data) => (
            <div key={data.name} className="flex items-center gap-2">
              <div className="w-3 h-3 rounded-full" style={{ backgroundColor: data.color }} />
              <div className="flex flex-col">
                <span className="text-xs font-medium text-gray-800">{data.name}</span>
                <span className="text-[10px] text-gray-400">${data.value.toFixed(2)}</span>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Bar Chart of Recent Spending */}
      <div className="bg-white rounded-3xl p-6 shadow-sm border border-gray-100">
        <h3 className="text-lg font-bold mb-4">Top Spending</h3>
        <div className="h-[200px] w-full">
           <ResponsiveContainer width="100%" height="100%">
            <BarChart data={categoryData.slice(0, 5)} layout="vertical">
              <XAxis type="number" hide />
              <YAxis 
                dataKey="name" 
                type="category" 
                axisLine={false} 
                tickLine={false} 
                tick={{ fontSize: 12, fontWeight: 500 }}
                width={80}
              />
              <Tooltip 
                formatter={(value: number) => [`$${value.toFixed(2)}`, '']}
                cursor={{ fill: 'transparent' }}
              />
              <Bar 
                dataKey="value" 
                radius={[0, 10, 10, 0]} 
                barSize={20}
                animationDuration={1500}
              >
                {categoryData.slice(0, 5).map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

