import React, { useState } from 'react';
import { Send, Loader2, Sparkles, Plus, X, Calendar } from 'lucide-react';
import { parseTransaction } from '../services/geminiService';
import { Transaction, Category } from '../types';
import { CATEGORY_CONFIG } from '../constants';
import { format, parse } from 'date-fns';

interface TransactionInputProps {
  onAddTransaction: (t: Omit<Transaction, 'id' | 'date'>, date: string) => void;
}

const TransactionInput: React.FC<TransactionInputProps> = ({ onAddTransaction }) => {
  const [input, setInput] = useState('');
  const [selectedDate, setSelectedDate] = useState(format(new Date(), 'yyyy-MM-dd'));
  const [isProcessing, setIsProcessing] = useState(false);
  const [suggestion, setSuggestion] = useState<{ description: string; amount: number; category: Category } | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isProcessing) return;

    setIsProcessing(true);
    try {
      const result = await parseTransaction(input);
      setSuggestion(result);
    } catch (error) {
      console.error(error);
    } finally {
      setIsProcessing(false);
    }
  };

  const confirmSuggestion = () => {
    if (suggestion) {
      // Parse the local date string to a Date object correctly
      const finalDate = parse(selectedDate, 'yyyy-MM-dd', new Date());
      const now = new Date();
      finalDate.setHours(now.getHours(), now.getMinutes(), now.getSeconds());

      onAddTransaction({
        description: suggestion.description,
        amount: suggestion.amount,
        category: suggestion.category
      }, finalDate.toISOString());

      setSuggestion(null);
      setInput('');
      setSelectedDate(format(new Date(), 'yyyy-MM-dd'));
    }
  };

  return (
    <div className="w-full">
      {!suggestion ? (
        <form onSubmit={handleSubmit} className="relative space-y-4">
          <div className="relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder='e.g., "Abercrombie jeans 50.99"'
              aria-label="Transaction description"
              className="w-full bg-white border border-gray-200 rounded-2xl py-4 pl-5 pr-14 shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-lg font-medium"
            />
            <button
              type="submit"
              disabled={isProcessing || !input.trim()}
              aria-label="Submit transaction"
              className="absolute right-2 top-2 bottom-2 w-10 bg-blue-500 text-white rounded-xl flex items-center justify-center disabled:bg-gray-200 transition-colors"
            >
              {isProcessing ? <Loader2 className="animate-spin" size={20} /> : <Send size={20} />}
            </button>
          </div>

          <div className="flex items-center gap-3 bg-white border border-gray-200 rounded-2xl py-3 px-5 shadow-sm">
            <Calendar size={18} className="text-gray-400" />
            <div className="flex-1">
               <label htmlFor="txn-date" className="text-[10px] font-bold text-gray-400 uppercase block mb-0.5">Transaction Date</label>
               <input 
                 id="txn-date"
                 type="date"
                 value={selectedDate}
                 onChange={(e) => setSelectedDate(e.target.value)}
                 className="w-full text-sm font-semibold bg-transparent focus:outline-none"
               />
            </div>
          </div>

          <div className="mt-2 flex items-center gap-1.5 px-1">
            <Sparkles size={14} className="text-blue-500" />
            <p className="text-[11px] font-medium text-gray-400 uppercase tracking-widest">Powered by Gemini</p>
          </div>
        </form>
      ) : (
        <div className="bg-white border-2 border-blue-500 rounded-2xl p-5 shadow-xl animate-in zoom-in-95 duration-200">
          <div className="flex justify-between items-start mb-4">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-blue-50 text-blue-500 rounded-lg">
                <Sparkles size={20} />
              </div>
              <h4 className="font-bold text-lg text-gray-900">AI Categorized</h4>
            </div>
            <button 
              onClick={() => setSuggestion(null)} 
              className="text-gray-400 hover:text-gray-600 p-1"
              aria-label="Dismiss suggestion"
            >
              <X size={20} />
            </button>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center py-3 border-y border-gray-50">
              <span className="text-gray-500 font-medium">Description</span>
              <input 
                value={suggestion.description}
                onChange={(e) => setSuggestion({...suggestion, description: e.target.value})}
                className="text-right font-bold focus:outline-none text-blue-600 bg-transparent"
              />
            </div>

            <div className="flex justify-between items-center py-3 border-b border-gray-50">
              <span className="text-gray-500 font-medium">Category</span>
              <div className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full" style={{ backgroundColor: CATEGORY_CONFIG[suggestion.category].color }} />
                <select 
                  value={suggestion.category}
                  onChange={(e) => setSuggestion({...suggestion, category: e.target.value as Category})}
                  className="bg-transparent font-bold appearance-none focus:outline-none text-blue-600 text-right cursor-pointer"
                >
                  {Object.values(Category).map(cat => (
                    <option key={`opt-${cat}`} value={cat}>{cat}</option>
                  ))}
                </select>
              </div>
            </div>

            <div className="flex justify-between items-center py-3 border-b border-gray-50">
              <span className="text-gray-500 font-medium">Date</span>
              <input 
                type="date"
                value={selectedDate}
                onChange={(e) => setSelectedDate(e.target.value)}
                className="text-right font-bold focus:outline-none text-blue-600 bg-transparent"
              />
            </div>

            <div className="flex justify-between items-center py-3 border-b border-gray-50">
              <span className="text-gray-500 font-medium">Amount</span>
              <div className="flex items-center text-blue-600 font-bold text-xl">
                <span>$</span>
                <input 
                  type="number"
                  step="0.01"
                  value={suggestion.amount}
                  onChange={(e) => setSuggestion({...suggestion, amount: parseFloat(e.target.value) || 0})}
                  className="w-24 text-right bg-transparent focus:outline-none"
                />
              </div>
            </div>
          </div>

          <button
            onClick={confirmSuggestion}
            className="w-full mt-6 bg-blue-500 text-white font-bold py-4 rounded-xl shadow-lg shadow-blue-200 active:scale-95 transition-all flex items-center justify-center gap-2"
          >
            <Plus size={20} />
            Add Transaction
          </button>
        </div>
      )}
    </div>
  );
};

export default TransactionInput;

import React, { useState, useEffect } from 'react';
import { LayoutGrid, PlusCircle, Settings, Wallet } from 'lucide-react';
import TopHeader from './components/TopHeader';
import Dashboard from './components/Dashboard';
import TransactionInput from './components/TransactionInput';
import TransactionList from './components/TransactionList';
import BudgetSetter from './components/BudgetSetter';
import { Transaction, Timeframe } from './types';
import { INITIAL_TRANSACTIONS } from './constants';

type Tab = 'Dashboard' | 'Add' | 'Transactions' | 'Budget';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('Dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('spendwise_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [budget, setBudget] = useState<number>(() => {
    const saved = localStorage.getItem('spendwise_budget');
    return saved ? parseFloat(saved) : 2000;
  });
  const [timeframe, setTimeframe] = useState<Timeframe>('Month');
  const [showBudgetModal, setShowBudgetModal] = useState(false);

  useEffect(() => {
    localStorage.setItem('spendwise_transactions', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('spendwise_budget', budget.toString());
  }, [budget]);

  const addTransaction = (t: Omit<Transaction, 'id' | 'date'>, date: string) => {
    const newTransaction: Transaction = {
      ...t,
      id: Math.random().toString(36).substr(2, 9),
      date: date,
    };
    setTransactions(prev => [newTransaction, ...prev]);
    setActiveTab('Transactions');
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'Dashboard':
        return (
          <Dashboard 
            transactions={transactions} 
            budget={budget} 
            timeframe={timeframe} 
            onTimeframeChange={setTimeframe} 
          />
        );
      case 'Add':
        return (
          <div className="px-5 pt-8 animate-in slide-in-from-bottom-4 duration-400">
            <h2 className="text-2xl font-bold mb-6 text-gray-900">New Transaction</h2>
            <TransactionInput onAddTransaction={addTransaction} />
            <div className="mt-8">
              <p className="text-gray-400 text-sm font-medium mb-4 uppercase tracking-wider">Examples</p>
              <div className="flex flex-wrap gap-2">
                {['Abercrombie jeans $50', 'Starbucks Latte 5.50', 'Shell Fuel 45.00', 'Grocery run at Trader Joes $110'].map((ex, idx) => (
                  <div key={`ex-${idx}`} className="bg-white border border-gray-100 rounded-xl px-4 py-2 text-sm text-gray-500 font-medium">
                    {ex}
                  </div>
                ))}
              </div>
            </div>
          </div>
        );
      case 'Transactions':
        return (
          <div className="animate-in slide-in-from-bottom-4 duration-400 mt-4">
             <TransactionList transactions={transactions} onDelete={deleteTransaction} />
          </div>
        );
      default:
        return null;
    }
  };

  const tabItems = [
    { id: 'Dashboard', icon: <LayoutGrid size={24} />, label: 'Overview' },
    { id: 'Add', icon: <PlusCircle size={28} className="text-blue-500" />, label: 'Add' },
    { id: 'Transactions', icon: <Wallet size={24} />, label: 'History' },
  ];

  return (
    <div className="max-w-md mx-auto h-screen bg-[#F2F2F7] flex flex-col relative shadow-2xl overflow-hidden border-x border-gray-200">
      <TopHeader 
        title={activeTab === 'Add' ? 'Add' : activeTab === 'Transactions' ? 'History' : 'Overview'} 
        rightElement={
          <button 
            onClick={() => setShowBudgetModal(true)}
            aria-label="Open settings"
            className="p-2 bg-gray-200/50 rounded-full text-gray-600 hover:bg-gray-200 active:scale-95 transition-all"
          >
            <Settings size={20} />
          </button>
        }
      />

      <main className="flex-1 overflow-y-auto hide-scrollbar">
        {renderContent()}
      </main>

      {/* Bottom Tab Bar */}
      <nav className="absolute bottom-0 left-0 right-0 bg-white/90 ios-blur pt-3 pb-8 px-8 flex justify-between items-center border-t border-gray-200 z-50">
        {tabItems.map((item) => (
          <button
            key={`tab-${item.id}`}
            onClick={() => setActiveTab(item.id as Tab)}
            aria-label={`Go to ${item.label}`}
            className={`flex flex-col items-center gap-1 transition-all active:scale-90 ${
              activeTab === item.id ? 'text-blue-500 scale-110' : 'text-gray-400'
            }`}
          >
            {item.icon}
            <span className="text-[10px] font-bold tracking-tight">{item.label}</span>
          </button>
        ))}
      </nav>

      {showBudgetModal && (
        <BudgetSetter 
          currentBudget={budget} 
          onUpdate={(val) => {
            setBudget(val);
            setShowBudgetModal(false);
          }}
          onClose={() => setShowBudgetModal(false)}
        />
      )}
    </div>
  );
};

