                <X size={24} />
              </button>
            </div>
            <div className="p-6 overflow-y-auto max-h-[calc(95vh-88px)]">
              <TransactionInput 
                initialData={editingTransaction} 
                onAddTransaction={handleSaveTransaction} 
                onCancel={() => setEditingTransaction(null)}
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

