import { GoogleGenAI, Type } from "@google/genai";
import { Category } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function parseTransactionWithAI(input: string) {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Parse the following spending note into a JSON object: "${input}". 
      Available categories: ${Object.values(Category).join(", ")}.
      If category is unclear, use 'Other'.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            amount: { type: Type.NUMBER, description: "The numeric cost" },
            vendor: { type: Type.STRING, description: "The place where money was spent" },
            description: { type: Type.STRING, description: "What was purchased" },
            category: { type: Type.STRING, description: "Must be one of the provided categories" }
          },
          required: ["amount", "vendor", "description", "category"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("AI Parsing Error:", error);
    throw error;
  }
}

